import { Link } from "react-router-dom";
import StatusDetails from "../../utils/StatusDetails";
import StatusDrop from "../../utils/StatusDrop";
import { v4 as uuidv4 } from 'uuid';
import { epochTogmt } from "../../utils/Common";
import authService from "src/auth/auth.service";

export const tableTeamConstant = (fetchTeamList, handleConfirmModal) => {
    return [
        {
            id: 1,
            name: "Position",
            cell: (row) => {
                return (
                    <Link to={`/team/edit/${row?.id}`}>
                        <span className="sub">{row.name}</span>
                    </Link>
                );
            },
            sortable: true,
            reorder: true,
            style: {
                color: "#202124",
                fontSize: "14px",
                fontWeight: 500,
            },
        },
        {
            id: 2,
            name: "Position",
            selector: (row) => row?.position
        },
        {
            id: 3,
            name: "Create Date",
            selector: (row) => epochTogmt(row?.createTime)
        },
        {
            id: 4,
            name: "Status",
            cell: (row) => {
                return (
                    <StatusDetails status={row.status} key={uuidv4()} />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 9,
            name: "Action",
            cell: (row) => {
                return (
                    <StatusDrop
                        id={row.id}
                        status={row.status}
                        type={'TEAM'}
                        action={fetchTeamList}
                        key={uuidv4()}
                        publishPermission={"TEAM_PUBLISH"}
                    />
                );
            },
            sortable: true,
            reorder: true,
        },
        {
            id: 4,
            name: "Delete",
            cell: (row) => {
                return <i className={"fa-regular fa-trash-can" + (row.status === "ENABLE" || !authService.getPermission("DELETE") ? " disable" : "")} onClick={(e) => { handleConfirmModal(row.id) }}></i>;
            },
            sortable: true,
            reorder: true,
        },
    ];
};
